sql:
SELECT DISTINCT suppliers.name
FROM suppliers
INNER JOIN registrations ON suppliers.supplier_id = registrations.supplier_id;

SELECT DISTINCT r.supplier_id
FROM registrations r
WHERE r.substance_id NOT IN (
    SELECT substance_id
    FROM regulatory_info
);

SELECT supplier_id, name 
FROM suppliers
WHERE supplier_id NOT IN (SELECT supplier_id FROM registrations);

SELECT ri.regulation, ri.compliance_status, COUNT(*) AS substance_count 
FROM regulatory_info AS ri 
GROUP BY ri.regulation, ri.compliance_status;

SELECT s.name, s.address, s.country, s.email, s.phone, s.website, s.date_registered
FROM suppliers AS s
JOIN (
    SELECT supplier_id, registration_date
    FROM registrations
    WHERE registration_date = (
        SELECT MAX(registration_date)
        FROM registrations
    )
) AS r ON s.supplier_id = r.supplier_id;
